import{_ as t,c as a,o,a1 as r}from"./chunks/framework.9hXSu8bi.js";const e="/mypatterndocs/static/%E9%A6%96%E9%A1%B5%E4%BB%8B%E7%BB%8D.BnQdkYbT.png",m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/帮助文档/功能介绍/首页.md","filePath":"zh/帮助文档/功能介绍/首页.md"}'),l={name:"zh/帮助文档/功能介绍/首页.md"},n=r('<h2 id="首页" tabindex="-1">首页 <a class="header-anchor" href="#首页" aria-label="Permalink to &quot;首页&quot;">​</a></h2><blockquote><p>首页是平台的默认视图，提供项目概览、地图快速定位及主要状态监控功能。</p></blockquote><p><img src="'+e+'" alt="" data-fancybox="gallery"></p><h3 id="_1-搜索栏" tabindex="-1">1. 搜索栏 <a class="header-anchor" href="#_1-搜索栏" aria-label="Permalink to &quot;1. 搜索栏&quot;">​</a></h3><ul><li><strong>项目搜索框</strong>：输入项目名称或关键字，快速筛选并定位到目标项目。</li><li><strong>重置视角</strong>：将地图视角恢复到初始默认位置和缩放级别，便于重新浏览。</li></ul><h3 id="_2-地图区域" tabindex="-1">2. 地图区域 <a class="header-anchor" href="#_2-地图区域" aria-label="Permalink to &quot;2. 地图区域&quot;">​</a></h3><ul><li><strong>地图界面</strong>：展示项目及子项目的地理位置分布，支持缩放、拖拽、点击图标查看项目详情。</li><li><strong>项目地址图标</strong>：显示当前选中项目的详细信息，例如状态、创建时间、未结项子项目等。</li></ul><h3 id="_3-项目状态" tabindex="-1">3. 项目状态 <a class="header-anchor" href="#_3-项目状态" aria-label="Permalink to &quot;3. 项目状态&quot;">​</a></h3><ul><li><strong>未结项</strong>：统计并展示尚未结项的项目数量，点击可快速筛选。</li><li><strong>结项</strong>：统计并展示已结项的项目数量，点击可快速筛选。</li><li><strong>图表分析</strong>：点击进入，可查看项目状态。</li></ul><h3 id="_4-悬浮窗" tabindex="-1">4. 悬浮窗 <a class="header-anchor" href="#_4-悬浮窗" aria-label="Permalink to &quot;4. 悬浮窗&quot;">​</a></h3><ul><li><strong>离线预警</strong>：显示设备离线导致的预警，点击可查看详情。</li><li><strong>图像曲线预警</strong>：展示基于图像或曲线触发的预警信息。</li><li><strong>数据处理</strong>：显示当前正在处理的数据任务状态（如地形融合、切片进度）。</li><li><strong>监测点/面计算</strong>：展示正在进行的监测点或监测面计算任务进度。</li></ul>',11),i=[n];function s(_,c,h,d,g,u){return o(),a("div",null,i)}const b=t(l,[["render",s]]);export{m as __pageData,b as default};
